// --- Flow Field Background Component ---
const FlowFieldBackground = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    let width = canvas.width = window.innerWidth;
    let height = canvas.height = window.innerHeight;

    class Particle {
      x: number;
      y: number;
      vx: number;
      vy: number;
      history: {x: number, y: number}[];
      maxLength: number;
      color: string;
      speed: number;

      constructor() {
        this.x = Math.random() * width;
        this.y = Math.random() * height;
        this.vx = 0;
        this.vy = 0;
        this.history = [];
        this.maxLength = Math.floor(Math.random() * 20 + 10);
        // Premium colors: Deep Blue, Gold, Cyan
        const colors = ['#3b82f6', '#0ea5e9', '#FFD700', '#B8860B'];
        this.color = colors[Math.floor(Math.random() * colors.length)];
        this.speed = Math.random() * 1 + 0.5;
      }

      update(angleField: number[][], cols: number) {
        const x = Math.floor(this.x / 20);
        const y = Math.floor(this.y / 20);

        // Ensure index is within bounds
        const index = y * cols + x;
        if (angleField[y] && angleField[y][x] !== undefined) {
           const angle = angleField[y][x];
           this.vx = Math.cos(angle) * this.speed;
           this.vy = Math.sin(angle) * this.speed;
        }

        this.x += this.vx;
        this.y += this.vy;

        this.history.push({x: this.x, y: this.y});
        if (this.history.length > this.maxLength) {
          this.history.shift();
        }

        if (this.x < 0) this.x = width;
        if (this.x > width) this.x = 0;
        if (this.y < 0) this.y = height;
        if (this.y > height) this.y = 0;
      }

      draw(context: CanvasRenderingContext2D) {
        context.beginPath();
        if (this.history.length > 0) {
            context.moveTo(this.history[0].x, this.history[0].y);
            for (let i = 1; i < this.history.length; i++) {
                context.lineTo(this.history[i].x, this.history[i].y);
            }
        }
        context.strokeStyle = this.color;
        context.lineWidth = 1; 
        context.globalAlpha = 0.4;
        context.stroke();
      }
    }

    const particles: Particle[] = [];
    const numberOfParticles = 250;
    const cellSize = 20;
    let rows: number;
    let cols: number;
    let flowField: number[][];

    const init = () => {
        width = canvas.width = window.innerWidth;
        height = canvas.height = window.innerHeight;
        rows = Math.floor(height / cellSize) + 1;
        cols = Math.floor(width / cellSize) + 1;
        flowField = [];

        // Generate noise-like flow field
        for (let y = 0; y < rows; y++) {
            const row = [];
            for (let x = 0; x < cols; x++) {
                const angle = (Math.cos(x * 0.05) + Math.sin(y * 0.05)) * Math.PI * 2;
                row.push(angle);
            }
            flowField.push(row);
        }

        particles.length = 0;
        for (let i = 0; i < numberOfParticles; i++) {
            particles.push(new Particle());
        }
    };

    const animate = () => {
        ctx.clearRect(0, 0, width, height);
        const time = Date.now() * 0.0005;
        for (let y = 0; y < rows; y++) {
            for (let x = 0; x < cols; x++) {
                const angle = (Math.cos(x * 0.02 + time) + Math.sin(y * 0.02 + time)) * Math.PI;
                if(flowField[y]) flowField[y][x] = angle;
            }
        }

        particles.forEach(p => {
            p.update(flowField, cols);
            p.draw(ctx);
        });
        requestAnimationFrame(animate);
    };

    init();
    window.addEventListener('resize', init);
    animate();

    return () => {
        window.removeEventListener('resize', init);
    };
  }, []);

  return <canvas ref={canvasRef} className="absolute inset-0 z-0 opacity-30 pointer-events-none" />;
};

